console.log("Contribution count:", testExport.humanContributions?.length === 2);
console.log("Both have timestamps:", 
  testExport.humanContributions?.every(c => c.collectedAt)
);
console.log("No duplicates:", 
  new Set(testExport.humanContributions.map(c => c.collectedAt)).size === 2
