      `Turns: ${GSA_STATE.processedTurns} / ${GSA_STATE.totalTurns}`;
  }

  function updateAlarm(message, ok = true) {
    const el = document.getElementById('gsa-alarm');
    el.innerText = message;
    el.style.color = ok ? '#0f0' : '#f00';
  }

