    Object.entries(SELECTORS).forEach(([key, sel]) => {
      if (key === 'turn') return;
      if (!document.querySelector(sel)) missing.push(key);
    });

    return {
      missing,
      ok: missing.length === 0,
      timestamp: new Date().toISOString()
    };
