    const userEl = turn.querySelector(SELECTORS.userText);
    if (userEl && userEl.innerText.trim()) {
      return { role: 'User', content: userEl.innerText.trim() };
    }

    const aiEl = turn.querySelector(SELECTORS.aiText);
    if (aiEl && aiEl.innerText.trim()) {
      return { role: 'AI', content: aiEl.innerText.trim() };
    }

    return null;
  }

  function extractThoughts(turn) {
    const el = turn.querySelector(SELECTORS.thoughtContent);
    return el && el.innerText.trim() ? el.innerText.trim() : null;
  }

