  async function startHarvest() {
    if (GSA_STATE.isRunning) return;

    GSA_STATE.isRunning = true;
    GSA_STATE.harvest = [];
    GSA_STATE.processedTurns = 0;

    const turns = Array.from(document.querySelectorAll(SELECTORS.turn));
    GSA_STATE.totalTurns = turns.length;

    updateCounter();

    GSA_STATE.diagnostics = diagnoseSelectors();
    updateAlarm(
      GSA_STATE.diagnostics.ok
        ? '✅ Selectors OK'
        : `⚠️ Missing: ${GSA_STATE.diagnostics.missing.join(', ')}`,
      GSA_STATE.diagnostics.ok
    );

    for (let i = 0; i < turns.length; i++) {
      const turn = turns[i];
      const dialogue = extractDialogue(turn);

      if (dialogue) {
        const entry = {
          index: i,
          role: dialogue.role,
          content: dialogue.content,
          timestamp: new Date().toISOString()
        };

        if (dialogue.role === 'AI' && detectThoughtPanel(turn)) {
          const thoughts = extractThoughts(turn);
          if (thoughts) entry.thoughts = thoughts;
        }

        GSA_STATE.harvest.push(entry);
      }

      GSA_STATE.processedTurns++;
      updateCounter();
      await new Promise(r => setTimeout(r, 120));
    }

    GSA_STATE.isRunning = false;
    document.getElementById('gsa-send').disabled = false;
