```javascript
// ==UserScript==
// @name         Safe Userscript Template v2.0 (Fortified)
// @version      2.0.0
// @description  Userscript met Syntax Check, Bracket Counter, Timeout, DOM Rollback & Audit Log
// @run-at       document-body
// ==/UserScript==

(function () {
  "use strict";

  /* ============================================================
     0. CONFIG
  ============================================================ */

  const SCRIPT_NAME = "SAFE-USER-SCRIPT";
  const CONFIG = {
    STRICT_MODE_CHECK: true,
    TIMEOUT_MS: 3000, // ⏱️ Max time allowance
    ENABLE_DOM_ROLLBACK: true, // 🧯 Undo changes on error
    ENABLE_BRACKET_CHECK: true // 🔢 Check balanced code
  };

  /* ============================================================
     🛠️ UTILS: AUDIT LOG (📜)
  ============================================================ */

  const Audit = {
    logs: [],
    log(action, details = "") {
      const entry = {
        time: new Date().toISOString(),
        action: `[${action}]`,
        details: details,
        location: window.location.href
      };
      this.logs.push(entry);
      console.log(`📜 ${entry.time} ${entry.action}:`, details);
    },
    dump() {
      console.table(this.logs);
      return this.logs;
    }
  };

  /* ============================================================
     1. SELF-CHECK (Validatie & 🔢 Bracket Counter)
  ============================================================ */

  function selfCheck(fn) {
    Audit.log("SELF-CHECK", "Starting static analysis...");

    try {
      const fnString = fn.toString();

      // 1️⃣ Syntax check (native parser)
      new Function(fnString);

      // 2️⃣ 🔢 Bracket Counter
      if (CONFIG.ENABLE_BRACKET_CHECK) {
        const stack = [];
        const pairs = { '(': ')', '[': ']', '{': '}' };
        // Simpele tokenizer die comments/strings negeert zou beter zijn, 
        // maar voor snelheid checken we hier pure balans.
        for (let char of fnString) {
          if (['(', '[', '{'].includes(char)) {
            stack.push(char);
          } else if ([')', ']', '}'].includes(char)) {
            const last = stack.pop();
            if (pairs[last] !== char) {
              throw new Error(`🔢 Bracket Mismatch! Expected closing for '${last}', found '${char}'.`);
            }
          }
        }
        if (stack.length > 0) {
          throw new Error(`🔢 Unclosed Brackets found: ${stack.join(', ')}`);
        }
        Audit.log("SELF-CHECK", "Bracket count balanced.");
      }

      Audit.log("SELF-CHECK", "Passed.");
      return true;
    } catch (err) {
      Audit.log("SELF-CHECK-FAIL", err.message);
      console.error(`❌ [${SCRIPT_NAME}] Self-check FAILED.`);
      alert(`[${SCRIPT_NAME}] Aborted.\n${err.message}`);
      return false;
    }
  }

  /* ============================================================
     🛠️ UTILS: DOM GUARD (🧯 Rollback)
  ============================================================ */

  const DOMGuard = {
    addedNodes: [],
    observer: null,

    start() {
      if (!CONFIG.ENABLE_DOM_ROLLBACK) return;
      Audit.log("DOM-GUARD", "Monitoring mutations...");

      this.observer = new MutationObserver((mutations) => {
        mutations.forEach((mutation) => {
          if (mutation.type === 'childList') {
            mutation.addedNodes.forEach((node) => {
              this.addedNodes.push(node);
            });
          }
        });
      });

      this.observer.observe(document.body, { childList: true, subtree: true });
    },

    stop() {
      if (this.observer) {
        this.observer.disconnect();
        Audit.log("DOM-GUARD", "Monitoring stopped.");
      }
    },

    rollback() {
      if (this.addedNodes.length === 0) return;

      Audit.log("ROLLBACK", `Reverting ${this.addedNodes.length} DOM changes...`);
